import React, { useEffect, useState } from "react";
import { Link, useNavigate } from 'react-router-dom';
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt } from "src/utils/Common";
import { CButton } from "@coreui/react";
import { deleteInterest, fetchAllInterestData } from "../../components/services/InterestApi";
import { tableInterestConstant } from "./tableInterestConstant";
import DataTable from "react-data-table-component";
import { customStyles } from "../../utils/tableCustomStyles";

const MySwal = withReactContent(alertPopUp);

const InterestList = () => {
    const [rowData, setRowData] = useState([]);

    useEffect(() => {
        fetchInterestList();
    }, []);

    const handleDelete = async (id) => {
        const response = await deleteInterest(id);
        if(response?.code === 200) {
            fetchInterestList();
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    const fetchInterestList = async () => {
        const response = await fetchAllInterestData();
        if(response?.code === 200) {
            setRowData(response?.results);
        }
    };

    return (<div className='row'>
       <div className="col2Large">
            <DataTable
                title="Interest"
                columns={tableInterestConstant(fetchInterestList, handleConfirmModal)}
                data={rowData}
                customStyles={customStyles}
                //actions={this.actionButton()}
                pagination
                paginationPerPage={10}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
            />
        </div>
        <div className='col-sm-12'>
            <Link to={"/interest/create"}>
                <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                    {"+ Create Interest"}
                </CButton>
            </Link>
        </div>
    </div>)
}

export default InterestList;
